{
  "operator_profile": "opus-compatible-claude-code",
  "decision_model": "host_defined_capability_policies",
  "intent": {
    "analysis_mode": "weak_request_shape_plus_prompt_envelope_host_boundaries_and_probe_shapes",
    "analysis": {
      "lexicon_guided": true
    },
    "actions": {
      "review": true
    },
    "output": {
      "structured": true
    },
    "tracks": [
      "review"
    ]
  },
  "workflow_owner": {
    "owner": "hello2cc",
    "mode": "native_routing",
    "reason": "no_visible_host_skill_workflow"
  },
  "policy": {
    "engine": "host_defined_capability_policies",
    "selection_mode": "model_chooses_within_host_bounds",
    "specificity_ladder": [
      "已加载 workflow / skill 连续体",
      "已 surfaced 的 skill / workflow",
      "已知 MCP resource",
      "已加载或已 surfaced 的 deferred tool",
      "ToolSearch / DiscoverSkills",
      "更宽的 Agent / Plan / team 路径"
    ],
    "request_tracks": [
      "review"
    ],
    "requested_output_shape": "findings_first_then_open_questions_then_change_summary"
  },
  "response_contract": {
    "role": "general_operator",
    "specialization": "review",
    "selection_basis": "weak_request_shape",
    "selection_strength": "weak",
    "selection_mode": "semantic_choice_within_candidates",
    "specialization_is_hint": true,
    "opening_style": "direct_no_internal_deliberation",
    "visible_text_language": "follow_user_language",
    "preferred_shape": "findings_first_then_open_questions_then_change_summary",
    "required_sections": [
      "findings",
      "open_questions",
      "change_summary"
    ],
    "prioritize_summary_first": true
  },
  "renderer_contract": {
    "style_name": "hello2cc:hello2cc Native",
    "style_source": "plugin_default",
    "opening": "findings_first",
    "section_order": [
      "findings",
      "open_questions",
      "change_summary"
    ],
    "table_mode": "markdown_when_helpful",
    "compact": true,
    "prefer_markdown": true,
    "ascii_only_when_needed": true,
    "preserve_higher_priority_format": true,
    "avoid": [
      "restyling_above_higher_priority_rules",
      "long_preamble_before_opening",
      "summary_before_findings"
    ]
  },
  "execution_playbook": {
    "role": "general_operator",
    "specialization": "review",
    "ordered_steps": [
      "collect_findings_with_paths",
      "rank_by_severity_or_regression_risk",
      "state_open_questions_after_findings"
    ],
    "avoid_shortcuts": [
      "summary_first_review"
    ]
  },
  "recovery_playbook": {
    "specialization": "review",
    "fail_closed": true,
    "retry_rule": "do_not_repeat_the_same_blocked_path_until_host_state_changes",
    "recipes": [
      {
        "guard": "review_findings_first",
        "recover_by": "list concrete findings with paths before any overview or change summary",
        "avoid": [
          "summary-only review output"
        ]
      }
    ]
  },
  "decision_tie_breakers": {
    "specialization": "review",
    "items": [
      {
        "id": "specific_surface_before_broader_path",
        "when": "more than one surfaced capability could work",
        "prefer": "the most specific visible surface or continuity first",
        "avoid": "jumping straight to a broader Agent, team, or discovery path"
      },
      {
        "id": "state_change_before_retry",
        "when": "a host guard or fail-closed path fired",
        "prefer": "the recovery_playbook path that changes state",
        "avoid": "repeating the same blocked attempt"
      },
      {
        "id": "findings_before_summary",
        "when": "the request is a review",
        "prefer": "findings with severity, behavior, and file references first",
        "avoid": "overview-first review output"
      }
    ]
  },
  "specialization_candidates": {
    "active": "review",
    "items": [
      {
        "id": "review",
        "reasons": [
          "hello2cc exposed review as a semantic route family",
          "request asks for review"
        ],
        "use_when": "need findings-first review output",
        "avoid_when": "the task is implementation rather than review",
        "recommended_shape": "findings_first_then_open_questions_then_change_summary",
        "selected": true,
        "selection_basis": "weak_request_shape",
        "selection_strength": "weak"
      },
      {
        "id": "capability",
        "reasons": [
          "hello2cc exposed capability as a semantic route family"
        ],
        "use_when": "the user is asking what Claude Code, tools, skills, workflows, MCP, or permissions can do here",
        "avoid_when": "the question is really about repo implementation rather than host capability surface",
        "recommended_shape": "direct_answer_then_visible_capabilities_then_gap_or_next_step"
      },
      {
        "id": "compare",
        "reasons": [
          "hello2cc exposed compare as a semantic route family"
        ],
        "use_when": "the user is comparing options, choosing between paths, or asking for tradeoffs",
        "avoid_when": "a stronger continuity or protocol path already owns the next step",
        "recommended_shape": "one_sentence_judgment_then_markdown_table_then_recommendation"
      },
      {
        "id": "explanation",
        "reasons": [
          "hello2cc exposed explanation as a semantic route family"
        ],
        "use_when": "the user wants a direct explanation, mechanism, or why/how answer anchored to visible context",
        "avoid_when": "the task is primarily execution, review, or verification",
        "recommended_shape": "direct_explanation_then_key_points_and_references"
      },
      {
        "id": "planning",
        "reasons": [
          "hello2cc exposed planning as a semantic route family"
        ],
        "use_when": "the user explicitly wants sequencing, phases, constraints, validation order, or an execution plan before coding",
        "avoid_when": "the next slice is already narrow enough to execute directly, or a read-only Plan/Explore helper can answer without entering session plan mode",
        "recommended_shape": "ordered_plan_with_validation_and_open_questions"
      },
      {
        "id": "release",
        "reasons": [
          "hello2cc exposed release as a semantic route family"
        ],
        "use_when": "the user is asking to version, tag, publish, or complete a release path",
        "avoid_when": "a stronger release-follow-up continuity candidate already owns the path",
        "recommended_shape": "release_status_then_checklist_then_notes"
      },
      {
        "id": "research",
        "reasons": [
          "hello2cc exposed research as a semantic route family"
        ],
        "use_when": "the user wants investigation, code reading, root-cause analysis, or path/symbol evidence before a conclusion",
        "avoid_when": "the slice is already a direct implementation or direct explanation task",
        "recommended_shape": "direct_findings_with_paths_and_unknowns"
      },
      {
        "id": "verification",
        "reasons": [
          "hello2cc exposed verification as a semantic route family"
        ],
        "use_when": "the user wants tests, validation evidence, pass/fail status, or explicit not-run boundaries",
        "avoid_when": "no validation evidence is needed for the current reply",
        "recommended_shape": "verification_status_then_evidence_then_gaps"
      }
    ]
  },
  "host": {
    "loaded_commands": [
      "effort"
    ]
  }
}
