+    JSON.stringify(selector),
+    selector.kind,
+    selector.root,
+    "cwd" in selector ? selector.cwd : null,
+    "fromDate" in selector ? selector.fromDate : null,
+    "toDate" in selector ? selector.toDate : null,
+    sourceFingerprint,
