1	import { DEFAULT_DB_PATH, INDEX_VERSION, ensureDataDir, resolveCodexDir } from "./env";
2	import {
3	  countSessionsForSelector,
4	  deleteSessionByFilePath,
5	  getIndexedSessionMeta,
6	  openWriteDb,
7	  replaceCoverage,
8	  replaceSession,
9	} from "./db";
10	import { parseCodexSession } from "./parser";
11	import { canonicalizeSelector } from "./selector";
12	import { collectSourceSnapshot } from "./source-inventory";
13	import { withSyncLock } from "./sync-lock";
14	import type { CoverageWriteSummary, ParsedSession, Selector, SyncErrorDetail, SyncSummary } from "./types";
15	
16	interface SyncOptions {
17	  dbPath?: string;
18	  rootDir?: string;
19	  selector?: Selector;
20	  bestEffort?: boolean;
21	}
22	
23	type SyncOperation =
24	  | {
25	      kind: "replace";
26	      filePath: string;
27	      session: ParsedSession;
28	      rawFileMtime: number;
29	      rawFileSize: number;
30	      pathDate: string;
31	      isUpdate: boolean;
32	    }
33	  | {
34	      kind: "filtered";
35	      filePath: string;
36	    };
37	
38	export class SyncError extends Error {
39	  summary: SyncSummary;
40	
41	  constructor(summary: SyncSummary) {
42	    super(buildSyncErrorMessage(summary));
43	    this.name = "SyncError";
44	    this.summary = summary;
45	  }
46	}
47	
48	export async function syncSessions(options: SyncOptions = {}): Promise<SyncSummary> {
49	  ensureDataDir();
50	  const dbPath = options.dbPath ?? DEFAULT_DB_PATH;
51	  const selector = canonicalizeSelector(options.selector ?? { kind: "all", root: resolveCodexDir(options.rootDir) });
52	  return withSyncLock(dbPath, async () => {
53	    const db = openWriteDb(dbPath);
54	    const sourceSnapshot = collectSourceSnapshot(selector);
55	    const operations: SyncOperation[] = [];
56	
57	    const summary: SyncSummary = {
58	      scanned: sourceSnapshot.fileCount,
59	      added: 0,
60	      updated: 0,
61	      skipped: 0,
62	      filtered: 0,
63	      errors: 0,
64	      errorDetails: [],
65	      selector,
66	      coverage: skippedCoverage(selector, sourceSnapshot.fingerprint, sourceSnapshot.fileCount, "not_written"),
67	    };
68	
69	    try {
70	      for (const file of sourceSnapshot.files) {
71	        const filePath = file.filePath;
72	        try {
73	          const indexed = getIndexedSessionMeta(db, filePath);
74	          if (isUnchanged(indexed, file.mtimeMs, file.size)) {
75	            summary.skipped += 1;
76	            continue;
77	          }
78	
79	          const parsed = await parseCodexSession(filePath);
80	          if (parsed.kind === "filtered") {
81	            operations.push({ kind: "filtered", filePath });
82	            continue;
83	          }
84	          if (parsed.kind === "skipped") {
85	            summary.skipped += 1;
86	            continue;
87	          }
88	
89	          operations.push({
90	            kind: "replace",
91	            filePath,
92	            session: parsed.session,
93	            rawFileMtime: file.mtimeMs,
94	            rawFileSize: file.size,
95	            pathDate: file.pathDate ?? "",
96	            isUpdate: Boolean(indexed),
97	          });
98	        } catch (error) {
99	          recordSyncError(summary, filePath, error);
100	        }
101	      }
102	
103	      if (summary.errors > 0 && !options.bestEffort) {
104	        throw new SyncError(summary);
105	      }
106	
107	      if (!options.bestEffort) {
108	        const afterSnapshot = collectSourceSnapshot(selector);
109	        if (afterSnapshot.fingerprint !== sourceSnapshot.fingerprint) {
110	          recordSyncError(summary, "(selector)", new Error("source changed during strict sync"));
111	          throw new SyncError(summary);
112	        }
113	      }
114	
115	      const bestEffort = Boolean(options.bestEffort);
116	      summary.coverage = applyOperations(db, operations, summary, bestEffort, selector, sourceSnapshot);
117	      if (summary.errors > 0 && !options.bestEffort) {
118	        throw new SyncError(summary);
119	      }
120	
