1	import { existsSync } from "node:fs";
2	import Database from "better-sqlite3";
3	import { tokenizedText } from "./tokenize";
4	import { INDEX_VERSION } from "./env";
5	import type {
6	  CoverageRecord,
7	  CwdCount,
8	  MessageRecord,
9	  ParsedSession,
10	  Selector,
11	  SessionListEntry,
12	  SessionListQuery,
13	  SessionRecord,
14	} from "./types";
15	import { selectorImplies, selectorStorageKey } from "./selector";
16	
17	type Db = Database.Database;
18	type SqlParams = unknown[];
19	
20	const BUSY_TIMEOUT_MS = 5000;
21	
22	export class IndexUnavailableError extends Error {
23	  constructor(public readonly dbPath: string) {
24	    super(`index not found: ${dbPath}`);
25	    this.name = "IndexUnavailableError";
26	  }
27	}
28	
29	export function openReadDb(dbPath: string): Db {
30	  if (!existsSync(dbPath)) {
31	    throw new IndexUnavailableError(dbPath);
32	  }
33	
34	  const db = new Database(dbPath, { readonly: true });
35	  db.pragma(`busy_timeout = ${BUSY_TIMEOUT_MS}`);
36	  db.pragma("query_only = ON");
37	  db.pragma("temp_store = MEMORY");
38	  return db;
39	}
40	
41	// Why: callers used to do `const db = openReadDb(...); ... db.close();` which
42	// leaks the connection if work in between throws. Wrapping in try/finally at
43	// every callsite is noise — fold it once.
44	export function withReadDb<T>(dbPath: string, fn: (db: Db) => T): T {
45	  const db = openReadDb(dbPath);
46	  try {
47	    return fn(db);
48	  } finally {
49	    db.close();
50	  }
51	}
52	
53	export function openWriteDb(dbPath: string): Db {
54	  const db = new Database(dbPath);
55	  db.pragma(`busy_timeout = ${BUSY_TIMEOUT_MS}`);
56	  db.pragma("journal_mode = WAL");
57	  db.pragma("synchronous = NORMAL");
58	  db.pragma("temp_store = MEMORY");
59	  db.pragma("foreign_keys = ON");
60	  ensureSchema(db);
61	  return db;
62	}
63	
64	function ensureSchema(db: Db): void {
65	  db.exec(`
66	    CREATE TABLE IF NOT EXISTS sessions (
67	      id INTEGER PRIMARY KEY AUTOINCREMENT,
68	      session_uuid TEXT NOT NULL UNIQUE,
69	      file_path TEXT NOT NULL UNIQUE,
70	      title TEXT NOT NULL DEFAULT '',
71	      summary_text TEXT NOT NULL DEFAULT '',
72	      compact_text TEXT NOT NULL DEFAULT '',
73	      reasoning_summary_text TEXT NOT NULL DEFAULT '',
74	      cwd TEXT NOT NULL DEFAULT '',
75	      model TEXT NOT NULL DEFAULT '',
76	      started_at TEXT NOT NULL,
77	      ended_at TEXT NOT NULL,
78	      path_date TEXT NOT NULL DEFAULT '',
79	      message_count INTEGER NOT NULL DEFAULT 0,
80	      raw_file_mtime INTEGER NOT NULL DEFAULT 0,
81	      raw_file_size INTEGER NOT NULL DEFAULT 0,
82	      index_version TEXT NOT NULL DEFAULT '',
83	      updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
84	    )
85	  `);
86	
87	  ensureTextColumn(db, "sessions", "summary_text");
88	  ensureTextColumn(db, "sessions", "compact_text");
89	  ensureTextColumn(db, "sessions", "reasoning_summary_text");
90	  ensureTextColumn(db, "sessions", "path_date");
91	
92	  db.exec(`
93	    CREATE TABLE IF NOT EXISTS messages (
94	      id INTEGER PRIMARY KEY AUTOINCREMENT,
95	      session_id INTEGER NOT NULL REFERENCES sessions(id) ON DELETE CASCADE,
96	      session_uuid TEXT NOT NULL,
97	      seq INTEGER NOT NULL,
98	      role TEXT NOT NULL,
99	      content_text TEXT NOT NULL,
100	      timestamp TEXT NOT NULL,
101	      source_kind TEXT NOT NULL,
102	      UNIQUE(session_uuid, seq)
103	    )
104	  `);
105	
106	  db.exec("CREATE INDEX IF NOT EXISTS idx_messages_session_seq ON messages(session_uuid, seq)");
107	  db.exec("CREATE INDEX IF NOT EXISTS idx_sessions_started_at ON sessions(started_at DESC)");
108	
109	  db.exec(`
110	    CREATE VIRTUAL TABLE IF NOT EXISTS messages_fts USING fts5(
111	      content_text,
112	      session_uuid UNINDEXED,
113	      seq UNINDEXED,
114	      role UNINDEXED,
115	      timestamp UNINDEXED,
116	      tokenize='unicode61 remove_diacritics 1'
117	    )
118	  `);
119	
120	  ensureSessionsFtsTable(db);
121	  ensureCoverageTable(db);
122	
123	  dropLegacyTrigramTable(db);
124	}
125	
126	function ensureCoverageTable(db: Db): void {
127	  db.exec(`
128	    CREATE TABLE IF NOT EXISTS coverage (
129	      id INTEGER PRIMARY KEY AUTOINCREMENT,
130	      selector_key TEXT NOT NULL UNIQUE,
131	      selector_json TEXT NOT NULL,
132	      selector_kind TEXT NOT NULL,
133	      root TEXT NOT NULL,
134	      cwd TEXT,
135	      from_date TEXT,
136	      to_date TEXT,
137	      source_fingerprint TEXT NOT NULL,
138	      source_file_count INTEGER NOT NULL,
139	      indexed_session_count INTEGER NOT NULL,
140	      completed_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
141	      index_version TEXT NOT NULL
142	    )
143	  `);
144	
145	  db.exec("CREATE INDEX IF NOT EXISTS idx_coverage_root ON coverage(root)");
146	}
147	
148	function dropLegacyTrigramTable(db: Db): void {
149	  // cxs <= v2 shipped a second FTS5 virtual table for CJK trigram search.
150	  // The hybrid bigram+Segmenter tokenizer in tokenize.ts replaces it, so
151	  // drop the old table and its shadow rows if they still exist.
152	  db.exec("DROP TABLE IF EXISTS messages_fts_trigram");
153	}
154	
155	function ensureSessionsFtsTable(db: Db): void {
156	  const existing = db
157	    .prepare("SELECT 1 FROM sqlite_master WHERE name = 'sessions_fts' LIMIT 1")
158	    .get();
159	
160	  if (existing) {
161	    const columns = db
162	      .prepare("PRAGMA table_info(sessions_fts)")
163	      .all() as Array<{ name: string }>;
164	    const names = new Set(columns.map((column) => column.name));
165	    if (!names.has("compact_text") || !names.has("reasoning_summary_text")) {
166	      db.exec("DROP TABLE sessions_fts");
167	    }
168	  }
169	
170	  db.exec(`
171	    CREATE VIRTUAL TABLE IF NOT EXISTS sessions_fts USING fts5(
172	      title,
173	      summary_text,
174	      compact_text,
175	      reasoning_summary_text,
176	      session_uuid UNINDEXED,
177	      tokenize='unicode61 remove_diacritics 1'
178	    )
179	  `);
180	}
181	
182	export function getIndexedSessionMeta(
183	  db: Db,
184	  filePath: string,
185	): { rawFileMtime: number; rawFileSize: number; indexVersion: string } | null {
186	  const row = db
187	    .prepare<[string], { rawFileMtime: number; rawFileSize: number; indexVersion: string }>(`
188	      SELECT raw_file_mtime AS rawFileMtime, raw_file_size AS rawFileSize, index_version AS indexVersion
189	      FROM sessions
190	      WHERE file_path = ?
191	      LIMIT 1
192	    `)
193	    .get(filePath) as
194	    | { rawFileMtime: number; rawFileSize: number; indexVersion: string }
195	    | undefined;
196	
197	  return row ?? null;
198	}
199	
200	export function deleteSessionByFilePath(db: Db, filePath: string): void {
201	  const row = db
202	    .prepare<[string], { sessionUuid: string }>("SELECT session_uuid AS sessionUuid FROM sessions WHERE file_path = ? LIMIT 1")
203	    .get(filePath) as { sessionUuid: string } | undefined;
204	
205	  if (!row) return;
206	  deleteSessionByUuid(db, row.sessionUuid);
207	}
208	
209	function deleteSessionByUuid(db: Db, sessionUuid: string): void {
210	  db.prepare("DELETE FROM sessions_fts WHERE session_uuid = ?").run(sessionUuid);
211	  db.prepare("DELETE FROM messages_fts WHERE session_uuid = ?").run(sessionUuid);
212	  db.prepare("DELETE FROM messages WHERE session_uuid = ?").run(sessionUuid);
213	  db.prepare("DELETE FROM sessions WHERE session_uuid = ?").run(sessionUuid);
214	}
215	
216	export function replaceSession(
217	  db: Db,
218	  session: ParsedSession,
219	  rawFileMtime: number,
220	  rawFileSize: number,
221	  indexVersion: string,
222	  pathDate: string,
223	): void {
224	  const tx = db.transaction(() => {
225	    const existing = db
226	      .prepare<[string, string], { id: number }>("SELECT id FROM sessions WHERE session_uuid = ? OR file_path = ? LIMIT 1")
227	      .get(session.sessionUuid, session.filePath) as { id: number } | undefined;
228	
229	    if (existing) {
230	      db.prepare(
231	        `
232	          UPDATE sessions
233	          SET session_uuid = ?, file_path = ?, title = ?, summary_text = ?, compact_text = ?, reasoning_summary_text = ?,
234	              cwd = ?, model = ?, started_at = ?, ended_at = ?, path_date = ?,
235	              message_count = ?, raw_file_mtime = ?, raw_file_size = ?, index_version = ?, updated_at = CURRENT_TIMESTAMP
236	          WHERE id = ?
237	        `,
238	      ).run(
239	        session.sessionUuid,
240	        session.filePath,
241	        session.title,
242	        session.summaryText,
243	        session.compactText ?? "",
244	        session.reasoningSummaryText ?? "",
245	        session.cwd,
246	        session.model,
247	        session.startedAt,
248	        session.endedAt,
249	        pathDate,
250	        session.messages.length,
251	        rawFileMtime,
252	        rawFileSize,
253	        indexVersion,
254	        existing.id,
255	      );
256	    } else {
257	      db.prepare(
258	        `
259	          INSERT INTO sessions (
260	            session_uuid, file_path, title, summary_text, compact_text, reasoning_summary_text,
261	            cwd, model, started_at, ended_at, path_date,
262	            message_count, raw_file_mtime, raw_file_size, index_version
263	          ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
264	        `,
265	      ).run(
266	        session.sessionUuid,
267	        session.filePath,
268	        session.title,
269	        session.summaryText,
270	        session.compactText ?? "",
271	        session.reasoningSummaryText ?? "",
272	        session.cwd,
273	        session.model,
274	        session.startedAt,
275	        session.endedAt,
276	        pathDate,
277	        session.messages.length,
278	        rawFileMtime,
279	        rawFileSize,
280	        indexVersion,
281	      );
282	    }
283	
284	    const sessionRow = db
285	      .prepare<[string], { id: number }>("SELECT id FROM sessions WHERE session_uuid = ? LIMIT 1")
286	      .get(session.sessionUuid) as { id: number };
287	
288	    db.prepare("DELETE FROM messages_fts WHERE session_uuid = ?").run(session.sessionUuid);
289	    db.prepare("DELETE FROM messages WHERE session_uuid = ?").run(session.sessionUuid);
290	    db.prepare("DELETE FROM sessions_fts WHERE rowid = ? OR session_uuid = ?").run(sessionRow.id, session.sessionUuid);
291	
292	    db.prepare(
293	      `
294	        INSERT INTO sessions_fts(rowid, title, summary_text, compact_text, reasoning_summary_text, session_uuid)
295	        VALUES (?, ?, ?, ?, ?, ?)
296	      `,
297	    ).run(
298	      sessionRow.id,
299	      tokenizedText(session.title),
300	      tokenizedText(session.summaryText),
301	      tokenizedText(session.compactText ?? ""),
302	      tokenizedText(session.reasoningSummaryText ?? ""),
303	      session.sessionUuid,
304	    );
305	
306	    const messageStmt = db.prepare<[number, string, number, string, string, string, string]>(`
307	      INSERT INTO messages (session_id, session_uuid, seq, role, content_text, timestamp, source_kind)
308	      VALUES (?, ?, ?, ?, ?, ?, ?)
309	    `);
310	    const ftsStmt = db.prepare<[number, string, string, number, string, string]>(`
311	      INSERT INTO messages_fts(rowid, content_text, session_uuid, seq, role, timestamp)
312	      VALUES (?, ?, ?, ?, ?, ?)
313	    `);
314	
315	    for (const message of session.messages) {
316	      const result = messageStmt.run(
317	        sessionRow.id,
318	        session.sessionUuid,
319	        message.seq,
320	        message.role,
321	        message.contentText,
322	        message.timestamp,
323	        message.sourceKind,
324	      );
325	      const messageId = Number(result.lastInsertRowid);
326	      // Feed the FTS index with tokenized text so that CJK runs are split
327	      // into bigrams by tokenize(). Stored content in messages.content_text
328	      // stays raw for display.
329	      ftsStmt.run(
330	        messageId,
331	        tokenizedText(message.contentText),
332	        session.sessionUuid,
333	        message.seq,
334	        message.role,
335	        message.timestamp,
336	      );
337	    }
338	  });
339	
340	  tx();
341	}
342	
