67	
68	    const rangeStartSeq = Math.max(0, anchorSeq - options.before);
69	    const rangeEndSeq = anchorSeq + options.after;
70	    const messages = getMessagesForRange(db, sessionUuid, rangeStartSeq, rangeEndSeq);
71	    return {
72	      session,
73	      anchorSeq,
