152	function resolveAnchorSeq(
153	  db: Db,
154	  sessionUuid: string,
155	  seq?: number,
156	  query?: string,
157	): number {
158	  if (typeof seq === "number") {
159	    return seq;
160	  }
161	
162	  if (query) {
163	    const best = searchTopHitInSession(db, sessionUuid, query);
164	    if (best && typeof best.matchSeq === "number") return best.matchSeq;
165	  }
166	
167	  throw new Error("read-range requires explicit session_uuid plus either --seq or --query");
168	}
