170	function searchTopHitInSession(db: Db, sessionUuid: string, query: string): FindResult | null {
171	  const rows = searchMessageHits(db, query, 20, sessionUuid);
172	  const result = rerankHits(rows, query, 1)[0];
173	  return result ?? null;
174	}
175	
176	function searchMessageHits(
177	  db: Db,
178	  query: string,
179	  limit: number,
180	  sessionUuid?: string,
181	  selector: Selector | null = null,
182	): RawHitRow[] {
183	  const normalized = query.trim();
184	  if (!normalized) return [];
185	
186	  const terms = queryTerms(normalized);
187	  // Queries that degenerate to zero tokens (e.g. a single kanji dropped as
188	  // stop-word-like noise, or whitespace only) cannot hit the FTS index. Fall
189	  // back to a bounded LIKE scan so single-character CJK probes still work
190	  // even though they are discouraged.
191	  if (terms.length === 0) {
192	    if (hasCjk(normalized)) return searchByLike(db, normalized, limit, sessionUuid, selector);
193	    return [];
