201	  if (!normalized || !tableExists(db, "sessions_fts")) return [];
202	
203	  const terms = queryTerms(normalized);
204	  if (terms.length === 0) return [];
205	
206	  return searchSessionsByFts(db, normalized, terms, limit, selector);
207	}
208	
209	function searchByFts(
210	  db: Db,
211	  terms: string[],
212	  limit: number,
213	  sessionUuid?: string,
214	  selector: Selector | null = null,
215	): RawHitRow[] {
216	  const matchExpr = buildFtsMatch(terms);
217	  const conditions = [`messages_fts MATCH ?`];
218	  const params: SqlParams = [matchExpr];
219	
220	  if (selector) {
221	    const selectorWhere = selectorWhereSql(selector, "s");
222	    conditions.push(...selectorWhere.conditions);
223	    params.push(...selectorWhere.params);
224	  }
225	  if (sessionUuid) {
226	    conditions.push("m.session_uuid = ?");
227	    params.push(sessionUuid);
228	  }
229	  params.push(limit);
230	
231	  return db
232	    .prepare<typeof params, RawHitRow>(`
233	      SELECT
234	        s.session_uuid AS sessionUuid,
235	        s.title AS title,
236	        s.summary_text AS summaryText,
237	        s.cwd AS cwd,
238	        s.started_at AS startedAt,
239	        s.ended_at AS endedAt,
240	        'message' AS matchSource,
241	        m.seq AS matchSeq,
242	        m.role AS matchRole,
243	        m.timestamp AS matchTimestamp,
244	        m.content_text AS contentText,
245	        snippet(messages_fts, 0, '<mark>', '</mark>', '…', 16) AS snippet,
246	        bm25(messages_fts) AS score
247	      FROM messages_fts
248	      JOIN messages m ON m.id = messages_fts.rowid
249	      JOIN sessions s ON s.id = m.session_id
250	      WHERE ${conditions.join(" AND ")}
251	      ORDER BY score
252	      LIMIT ?
