551	export function listCoverageRecords(db: Db): CoverageRecord[] {
552	  if (!tableExists(db, "coverage")) return [];
553	  const rows = db.prepare("SELECT * FROM coverage ORDER BY completed_at DESC, id DESC").all() as CoverageRow[];
554	  return rows.map(rowToCoverageRecord);
555	}
556	
557	export function coverageStatusForSelector(db: Db, requested: Selector | null): {
558	  complete: boolean;
559	  coveringSelectors: CoverageRecord[];
560	} {
561	  if (!requested) return { complete: false, coveringSelectors: [] };
562	  const entries = listCoverageRecords(db).filter((entry) =>
563	    entry.indexVersion === requestedIndexVersion(db) && selectorImplies(entry.selector, requested)
564	  );
565	  return {
566	    complete: entries.length > 0,
567	    coveringSelectors: entries,
568	  };
569	}
570	
571	export function countSessionsForSelector(db: Db, selector: Selector): number {
572	  const where = selectorWhereSql(selector, "sessions");
573	  const row = db
574	    .prepare<typeof where.params, { count: number }>(`
575	      SELECT COUNT(*) AS count
576	      FROM sessions
577	      WHERE ${where.conditions.join(" AND ")}
578	    `)
579	    .get(...where.params) as { count: number };
580	  return row.count;
581	}
582	
583	export function selectorWhereSql(selector: Selector, alias: string): { conditions: string[]; params: SqlParams } {
584	  const conditions = [`(${alias}.file_path = ? OR ${alias}.file_path LIKE ? ESCAPE '\\')`];
585	  const params: SqlParams = [selector.root, `${escapeLike(selector.root)}/%`];
586	  if (selector.kind === "cwd" || selector.kind === "cwd_date_range") {
587	    conditions.push(`${alias}.cwd = ?`);
588	    params.push(selector.cwd);
589	  }
590	  if (selector.kind === "date_range" || selector.kind === "cwd_date_range") {
591	    conditions.push(`${alias}.path_date >= ?`);
592	    conditions.push(`${alias}.path_date <= ?`);
593	    params.push(selector.fromDate, selector.toDate);
594	  }
595	  return { conditions, params };
596	}
597	
598	export function coverageEntriesForSession(db: Db, session: SessionRecord): CoverageRecord[] {
599	  const sessionSelectors: Selector[] = [
600	    { kind: "all", root: sessionRootFromFile(session.filePath) },
601	    { kind: "cwd", root: sessionRootFromFile(session.filePath), cwd: session.cwd },
602	  ];
603	  if (session.pathDate) {
604	    sessionSelectors.push({
605	      kind: "date_range",
606	      root: sessionRootFromFile(session.filePath),
607	      fromDate: session.pathDate,
608	      toDate: session.pathDate,
609	    });
610	    sessionSelectors.push({
611	      kind: "cwd_date_range",
612	      root: sessionRootFromFile(session.filePath),
613	      cwd: session.cwd,
614	      fromDate: session.pathDate,
615	      toDate: session.pathDate,
616	    });
617	  }
618	  return listCoverageRecords(db).filter((entry) =>
619	    sessionSelectors.some((selector) => selectorImplies(entry.selector, selector))
620	  );
621	}
