623	type CoverageRow = {
624	  id: number;
625	  selector_json: string;
626	  source_fingerprint: string;
627	  source_file_count: number;
628	  indexed_session_count: number;
629	  completed_at: string;
630	  index_version: string;
631	};
632	
633	function getCoverageRecordByKey(db: Db, key: string): CoverageRecord | null {
634	  const row = db.prepare<[string], CoverageRow>("SELECT * FROM coverage WHERE selector_key = ? LIMIT 1").get(key);
635	  return row ? rowToCoverageRecord(row) : null;
636	}
637	
638	function rowToCoverageRecord(row: CoverageRow): CoverageRecord {
639	  return {
640	    id: row.id,
641	    selector: JSON.parse(row.selector_json) as Selector,
642	    sourceFingerprint: row.source_fingerprint,
643	    sourceFileCount: row.source_file_count,
644	    indexedSessionCount: row.indexed_session_count,
645	    completedAt: row.completed_at,
646	    indexVersion: row.index_version,
647	  };
648	}
649	
650	function tableExists(db: Db, tableName: string): boolean {
651	  const row = db.prepare<[string], unknown>("SELECT 1 FROM sqlite_master WHERE name = ? LIMIT 1").get(tableName);
652	  return Boolean(row);
653	}
654	
655	function requestedIndexVersion(_db: Db): string {
656	  // Kept as a function so coverage matching has one place for future index
657	  // compatibility policy; current policy is exact index version equality.
658	  return INDEX_VERSION;
659	}
660	
661	function sessionRootFromFile(filePath: string): string {
662	  const marker = "/sessions/";
663	  const index = filePath.indexOf(marker);
664	  if (index >= 0) return filePath.slice(0, index + marker.length - 1);
665	  return filePath.slice(0, Math.max(0, filePath.lastIndexOf("/")));
666	}
